"""Generate 400 new plot_coherence samples to reach 500 total."""
import json

def make_sample(sid, genre, diff, ctx, agent_out, score, rationale, expected, evals, neg=False, err=None):
    return {
        "sample_id": sid, "genre": genre, "difficulty": diff,
        "input": {"preceding_context": ctx, "user_request": "请续写接下来的情节"},
        "output": {"text": agent_out},
        "reference": {"coherence_score": score, "rationale": rationale, "contradiction_types": [] if not neg else [err], "expected_behavior": expected},
        "evaluation": evals,
        "negative_sample": neg,
        "error_type": err
    }

def good_evals(nc, pc=5, wc=5, gf=5, fth=0.9, hal=0.1, cr=0.85):
    return {"narrative_coherence": nc, "plot_continuity": pc, "world_consistency": wc, "genre_fidelity": gf, "faithfulness": fth, "hallucination": hal, "context_recall": cr}

def bad_evals(nc=1, pc=1, wc=1, gf=3, fth=0.1, hal=0.9, cr=0.1):
    return {"narrative_coherence": nc, "plot_continuity": pc, "world_consistency": wc, "genre_fidelity": gf, "faithfulness": fth, "hallucination": hal, "context_recall": cr}

