for item in negatives:
    sid, diff, ctx, out, score, rat = item[0], item[1], item[2], item[3], item[4], item[5]
    err = item[6] if isinstance(item[6], str) and item[6] != "" else None
    genre = item[1]
    all_samples.append(make_sample(sid, genre, diff, ctx, out, score, rat, "", bad_evals(), neg=True, err=err))

