import os

base_dir = "evaluation_datasets/plot_coherence"
samples_dir = os.path.join(base_dir, "samples")
negative_dir = os.path.join(base_dir, "negative")
os.makedirs(samples_dir, exist_ok=True)
os.makedirs(negative_dir, exist_ok=True)

# Write new genre files (exclude negatives)
genre_files = {
    "xuanhuan": [s for s in all_samples if s["genre"] == "xuanhuan" and not s["negative_sample"]],
    "historical": [s for s in all_samples if s["genre"] == "historical" and not s["negative_sample"]],
    "sci_fi": [s for s in all_samples if s["genre"] == "sci_fi" and not s["negative_sample"]],
    "mystery": [s for s in all_samples if s["genre"] == "mystery" and not s["negative_sample"]],
    "light_novel": [s for s in all_samples if s["genre"] == "light_novel" and not s["negative_sample"]],
}
for genre, samples in genre_files.items():
    path = os.path.join(samples_dir, f"{genre}.jsonl")
    with open(path, "w", encoding="utf-8") as f:
        for s in samples:
            f.write(json.dumps(s, ensure_ascii=False) + "\n")
    print(f"  {path}: {len(samples)} samples")

# Write append files for existing genres (exclude negatives)
append_genres = {
    "xianxia": [s for s in all_samples if s["genre"] == "xianxia" and not s["negative_sample"]],
    "urban": [s for s in all_samples if s["genre"] == "urban" and not s["negative_sample"]],
    "western_fantasy": [s for s in all_samples if s["genre"] == "western_fantasy" and not s["negative_sample"]],
}
for genre, samples in append_genres.items():
    path = os.path.join(samples_dir, f"{genre}_append.jsonl")
    with open(path, "w", encoding="utf-8") as f:
        for s in samples:
            f.write(json.dumps(s, ensure_ascii=False) + "\n")
    print(f"  {path}: {len(samples)} samples (to append)")

# Write negatives
neg_samples = [s for s in all_samples if s["negative_sample"]]
neg_path = os.path.join(negative_dir, "02_mixed_negatives.jsonl")
with open(neg_path, "w", encoding="utf-8") as f:
    for s in neg_samples:
        f.write(json.dumps(s, ensure_ascii=False) + "\n")
print(f"\nTotal new samples generated: {len(all_samples)}")
print(f"  Positive: {len([s for s in all_samples if not s['negative_sample']])}")
print(f"  Negative: {len(neg_samples)}")
